effect.shader:
void main() {
    if( strength <= 0.005 ) {
        gl_FragColor = texture2DCv(inputImg.texture,acScreenNorm);
    } else {
        if( acPass==0 ) {
            gl_FragColor = texture2DCv(inputImg.texture,acScreenNorm);
        } else if( acPass==1 ) {
            gl_FragColor = texture2DCv(ds1.texture,acScreenNorm);
        } else if( acPass==2 ) {

            float angle = 0.0;
            float actualStrength = strength/4.0/iter;

            vec2 texelSize = 1.0 / vec2(ds2.size);
            float rad = angle * 0.0174533;
            vec2 velocity = vec2(cos(rad)*actualStrength,-sin(rad)*actualStrength);
            float speed = length(velocity / texelSize);
            int nSamples = int(clamp(speed, 2.01, 100.01));
            vec4 outColor = texture2DCv(ds2.texture,acScreenNorm.st);
            for(int i=1; i<nSamples; i++ ) {
                vec2 offset = velocity * (float(i) / float(nSamples - 1));
                outColor += texture2DCv(ds2.texture, acScreenNorm.st+offset);
                outColor += texture2DCv(ds2.texture, acScreenNorm.st-offset);
            }
            vec4 result = outColor/float(nSamples*2-1);
            gl_FragColor = result;
        } else {

            float angle = 90.0;
            float actualStrength = strength/4.0/iter;

            vec2 texelSize = 1.0 / vec2(hblur.size);
            float rad = angle * 0.0174533;
            vec2 velocity = vec2(cos(rad)*actualStrength,-sin(rad)*actualStrength);
            float speed = length(velocity / texelSize);
            int nSamples = int(clamp(speed, 2.01, 100.01));
            vec4 outColor = texture2DCv(hblur.texture,acScreenNorm.st);
            for(int i=1; i<nSamples; i++ ) {
                vec2 offset = velocity * (float(i) / float(nSamples - 1));
                outColor += texture2DCv(hblur.texture, acScreenNorm.st+offset);
                outColor += texture2DCv(hblur.texture, acScreenNorm.st-offset);
            }
            vec4 result = outColor/float(nSamples*2-1);
            gl_FragColor = result;

        }
    }
}
